+export function requireScopes(...scopes: string[]) {
+  return (req, res, next) => {
+    const tokenScopes = req.user?.scopes ?? [];
+    const hasAll = scopes.every(s => tokenScopes.includes(s));
+    if (!hasAll) return res.status(403).json({ error: 'Insufficient scope' });
+    next();
+  };
+}

